with open("app/main.py", "w", encoding="utf-8", newline="\n") as f:
    f.write("""from fastapi import FastAPI\nfrom pydantic import BaseModel, Field\nimport joblib\nimport numpy as np\n\napp = FastAPI(title="Gym Injury Risk Predictor")\n\nmodel = joblib.load("model/model.pkl")\nscaler = joblib.load("model/scaler.pkl")\n\nprint("Model loaded!")\n\nclass WorkoutInput(BaseModel):\n    age: int = Field(..., ge=16, le=100)\n    bmi: float = Field(..., ge=10, le=60)\n    experience_years: float = Field(..., ge=0, le=50)\n    weight_lifted_kg: float = Field(..., ge=1, le=500)\n    sets: int = Field(..., ge=1, le=20)\n    reps: int = Field(..., ge=1, le=100)\n    rest_days: int = Field(..., ge=0, le=14)\n    sleep_hours: float = Field(..., ge=0, le=24)\n    warm_up_done: int = Field(..., ge=0, le=1)\n    past_injury: int = Field(..., ge=0, le=1)\n\nclass PredictionOutput(BaseModel):\n    injury_risk_probability: float\n    risk_level: str\n    recommendation: str\n\ndef get_risk_level(prob):\n    if prob < 0.3:\n        return "LOW"\n    elif prob < 0.6:\n        return "MEDIUM"\n    else:\n        return "HIGH"\n\ndef get_recommendation(risk, data):\n    if risk == "LOW":\n        return "Safe to train! Maintain good form."\n    elif risk == "MEDIUM":\n        return "Moderate risk. Reduce weight, warm up, sleep 7+ hrs."\n    else:\n        tips = []\n        if data.weight_lifted_kg > 100:\n            tips.append("reduce weight")\n        if data.rest_days < 2:\n            tips.append("rest 2 more days")\n        if data.warm_up_done == 0:\n            tips.append("do a warm-up")\n        if data.sleep_hours < 7:\n            tips.append("sleep more")\n        if data.past_injury == 1:\n            tips.append("see a physiotherapist")\n        return "HIGH RISK! Please: " + ", ".join(tips) + "."\n\n@app.get("/")\ndef home():\n    return {"message": "Gym Injury Risk API is running!"}\n\n@app.get("/health")\ndef health():\n    return {"status": "healthy"}\n\n@app.post("/predict", response_model=PredictionOutput)\ndef predict(data: WorkoutInput):\n    features = np.array([[data.age, data.bmi, data.experience_years, data.weight_lifted_kg, data.sets, data.reps, data.rest_days, data.sleep_hours, data.warm_up_done, data.past_injury]])\n    features_scaled = scaler.transform(features)\n    probability = float(model.predict_proba(features_scaled)[0][1])\n    risk = get_risk_level(probability)\n    return PredictionOutput(injury_risk_probability=round(probability, 3), risk_level=risk, recommendation=get_recommendation(risk, data))\n""")
print("Done!")
